105	    @Override
106	    public void buffer() {
107	        if (bufferedEntity == null) {
108	            try (InputStream is = createInputStream()) {
109	                try (ByteArrayOutputStream bos = new ByteArrayOutputStream()) {
110	                    byte[] buffer = new byte[BUFFER_SIZE];
111	                    int read;
112	                    int entityLength = 0;
113	                    while ((read = is.read(buffer)) != -1) {
114	                        entityLength += read;
