130	    public <T> T as(Class<T> type) {
131	        if (InputStream.class.equals(type)) {
132	            return (T) inputStream();
133	        }
134	
135	        if (byte[].class.equals(type)) {
136	            return (T) readAllBytes();
137	        }
138	
139	        if (String.class.equals(type)) {
